{
    "level": "A2",
    "intro": "Ця сторінка збирає в одному місці <strong>основні граматичні патерни курсу Polyglot English A2</strong>, щоб перед фінальним уроком ти міг швидко повторити вже знайомі структури.",
    "rules": [
        {
            "label": "TIME AND EXPERIENCE",
            "color": "blue",
            "text": "Повтори <strong>Present Perfect</strong>, контраст із <strong>Past Simple</strong> та типові time expressions.",
            "example": "I have just finished the report. / She visited Paris in 2022."
        },
        {
            "label": "PATTERNS AND LINKS",
            "color": "emerald",
            "text": "Зверни увагу на <strong>gerund vs infinitive, relative clauses, passive voice, reported speech</strong>.",
            "example": "She decided to learn Spanish. / This is the woman who works with my brother. / She said that she was tired."
        },
        {
            "label": "CONDITIONS AND REVIEW",
            "color": "rose",
            "text": "Перед фінальним drill важливо не плутати <strong>first conditional, second conditional, used to, question tags, be going to, should, have to</strong>.",
            "example": "We will go to the beach if it is sunny. / I would buy this house if I had more money. / You are not ready, are you?"
        }
    ]
}

{
    "title": "2. Контрольний список перед уроком 16",
    "intro": "Швидка самоперевірка перед фінальним міксом тем:",
    "items": [
        {
            "label": "Перевірка 1",
            "title": "Time marker чи open time?",
            "subtitle": "Не плутай Present Perfect з Past Simple, коли є finished time marker."
        },
        {
            "label": "Перевірка 2",
            "title": "If + present чи if + past?",
            "subtitle": "First Conditional і Second Conditional мають різні значення та форми."
        },
        {
            "label": "Перевірка 3",
            "title": "Infinitive чи gerund?",
            "subtitle": "Після mind, enjoy, decide та інших базових дієслів тримай правильний pattern."
        },
        {
            "label": "Перевірка 4",
            "title": "Auxiliary у question tag",
            "subtitle": "Tag має повторювати correct auxiliary і correct pronoun."
        }
    ]
}

